do $$
declare
  v_category_id uuid;
  v_subcategory_id uuid;
  v_law_id uuid;
  v_question_id uuid;
  v_article_id uuid;
  r record;
begin
  insert into public.categories(slug, title, description, sort_order, is_active)
  values ('constitutional', 'კონსტიტუციური სამართალი', 'კონსტიტუციური სამართლის ტესტები.', 5, true)
  on conflict (slug) do update set title=excluded.title, description=excluded.description, is_active=true
  returning id into v_category_id;

  insert into public.subcategories(category_id, title, slug)
  values (v_category_id, 'სიტყვისა და გამოხატვის თავისუფლების შესახებ', 'freedom-of-expression')
  on conflict (category_id, slug) do update set title=excluded.title
  returning id into v_subcategory_id;

  insert into public.laws(slug, title, short_title, direction_slug, description, current_version_date, is_active, needs_review, sort_order)
  values ('freedom-of-expression', 'საქართველოს კანონი „სიტყვისა და გამოხატვის თავისუფლების შესახებ“', 'სიტყვისა და გამოხატვის თავისუფლების შესახებ', 'constitutional', 'საქართველოს კანონის „სიტყვისა და გამოხატვის თავისუფლების შესახებ“ მიხედვით შედგენილი სიტყვასიტყვითი და კაზუსური ტესტები.', '2025-06-26'::date, true, false, 40)
  on conflict (slug) do update
  set title=excluded.title, short_title=excluded.short_title, direction_slug=excluded.direction_slug, description=excluded.description, current_version_date=excluded.current_version_date, is_active=true, needs_review=false
  returning id into v_law_id;

  delete from public.questions where law_id = v_law_id;

  for r in select * from (values
    ('მუხლი 1', 'ტერმინთა განმარტება'),
    ('მუხლი 2', 'კანონის ინტერპრეტირება'),
    ('მუხლი 3', 'სიტყვისა და გამოხატვის თავისუფლება'),
    ('მუხლი 4', 'აზრისა და მოწოდების თავისუფლება'),
    ('მუხლი 5', 'პოლიტიკური და სასამართლო სიტყვის თავისუფლება'),
    ('მუხლი 6', 'სასამართლო გარანტიები'),
    ('მუხლი 7', 'მტკიცებულების სტანდარტი და ტვირთი'),
    ('მუხლი 8', 'სიტყვისა და გამოხატვის თავისუფლების შეზღუდვის საფუძვლები'),
    ('მუხლი 9', 'შინაარსობრივი რეგულირება'),
    ('მუხლი 10', 'შინაარსობრივად ნეიტრალური რეგულირება'),
    ('მუხლი 11', 'პროფესიული საიდუმლოებისა და მისი წყაროს დაცვა'),
    ('მუხლი 12', 'პასუხისმგებლობა საიდუმლოების გამხელისათვის'),
    ('მუხლი 13', 'კერძო პირის ცილისწამება'),
    ('მუხლი 14', 'საჯარო პირის ცილისწამება'),
    ('მუხლი 15', '(ამოღებულია)'),
    ('მუხლი 16', 'ცილისწამებისათვის პასუხისმგებლობის ფარგლები'),
    ('მუხლი 17', 'ცილისწამებით მიყენებული ზიანის ანაზღაურება'),
    ('მუხლი 18', 'ცილისწამების შესახებ უსაფუძვლო სარჩელი'),
    ('მუხლი 19', 'სასარჩელო ხანდაზმულობის ვადა'),
    ('მუხლი 20', 'ძალადაკარგული აქტი'),
    ('მუხლი 21', 'კანონის ამოქმედება')
  ) as a(article_number, title)
  loop
    insert into public.law_articles(law_id, article_number, title, version_date, is_active)
    values (v_law_id, r.article_number, r.title, '2025-06-26'::date, true)
    on conflict (law_id, article_number) do update set title=excluded.title, version_date=excluded.version_date, is_active=true;
  end loop;

  for r in select * from (values
    ('constitutional', 'freedom-of-expression', 'საქართველოს კანონი „სიტყვისა და გამოხატვის თავისუფლების შესახებ“-ის მიხედვით, რა მიიჩნევა „განცხადებად“?', 'easy', 'სწორი პასუხია A, რადგან საქართველოს კანონი „სიტყვისა და გამოხატვის თავისუფლების შესახებ“ მუხლი 1 ადგენს, რომ განცხადება არის ინფორმაცია, რომელიც განმცხადებელმა საჯაროდ გაავრცელა ან მესამე პირს გააცნო.', 'საქართველოს კანონი „სიტყვისა და გამოხატვის თავისუფლების შესახებ“', 'მუხლი 1', '', '2025-06-26', false, 'საჯაროდ გავრცელებული ან მესამე პირისთვის გაცნობილი ინფორმაცია', 'მხოლოდ სასამართლოში წარდგენილი წერილობითი მოთხოვნა', 'მხოლოდ ადმინისტრაციული ორგანოს ოფიციალური აქტი', 'ნებისმიერი შიდა ჩანაწერი, რომელიც არავის გაცნობია', 'A'),
    ('constitutional', 'freedom-of-expression', 'საქართველოს კანონი „სიტყვისა და გამოხატვის თავისუფლების შესახებ“-ის მიხედვით, რომელი აღწერა შეესაბამება „აზრს“?', 'easy', 'სწორი პასუხია B, რადგან საქართველოს კანონი „სიტყვისა და გამოხატვის თავისუფლების შესახებ“ მუხლი 1 ადგენს, რომ აზრი არის შეფასებითი მსჯელობა ან შეხედულება, რომელიც არ შეიცავს დადასტურებად ან უარყოფად ფაქტს.', 'საქართველოს კანონი „სიტყვისა და გამოხატვის თავისუფლების შესახებ“', 'მუხლი 1', '', '2025-06-26', false, 'დადასტურებადი ფაქტის შემცველი ოფიციალური ცნობა', 'შეფასებითი მსჯელობა, რომელიც ფაქტს არ ამტკიცებს', 'სახელმწიფო საიდუმლოების შემცველი დოკუმენტი', 'კომერციული საიდუმლოების შემცველი გარიგება', 'B'),
    ('constitutional', 'freedom-of-expression', 'საქართველოს კანონი „სიტყვისა და გამოხატვის თავისუფლების შესახებ“-ის მიხედვით, რა არის „გამოხატვის საგანი“?', 'easy', 'სწორი პასუხია C, რადგან საქართველოს კანონი „სიტყვისა და გამოხატვის თავისუფლების შესახებ“ მუხლი 1 ადგენს, რომ გამოხატვის საგანი არის თემა ან საკითხი, რომლის შესახებაც მიმდინარეობს მსჯელობა და თვალსაზრისის გამოხატვა.', 'საქართველოს კანონი „სიტყვისა და გამოხატვის თავისუფლების შესახებ“', 'მუხლი 1', '', '2025-06-26', false, 'პირი, რომელიც განცხადებას საჯაროდ ავრცელებს', 'ფორმა, რომლითაც განცხადება ვრცელდება მედიაში', 'თემა ან საკითხი, რომლის შესახებაც მიმდინარეობს მსჯელობა', 'სასამართლო გადაწყვეტილება გამოხატვის შეზღუდვაზე', 'C'),
    ('constitutional', 'freedom-of-expression', 'საქართველოს კანონი „სიტყვისა და გამოხატვის თავისუფლების შესახებ“-ის მიხედვით, რომელი შემთხვევა უფრო შეესაბამება „მოწოდების“ ცნებას?', 'medium', 'სწორი პასუხია D, რადგან საქართველოს კანონი „სიტყვისა და გამოხატვის თავისუფლების შესახებ“ მუხლი 1 ადგენს, რომ მოწოდება არის განცხადება, რომლის ავტორი მიზნად ისახავს ან აშკარად უშვებს გარკვეული ქმედების გამოწვევას.', 'საქართველოს კანონი „სიტყვისა და გამოხატვის თავისუფლების შესახებ“', 'მუხლი 1', '', '2025-06-26', false, 'პირის პირადი დღიური, რომელიც არავის უნახავს', 'სასამართლოს მიერ გამოცემული სავალდებულო აქტი', 'საგადასახადო დეკლარაციის ტექნიკური ჩანაწერი', 'განცხადება, რომლითაც ავტორი ქმედების გამოწვევას მიზნად ისახავს', 'D'),
    ('constitutional', 'freedom-of-expression', 'საქართველოს კანონი „სიტყვისა და გამოხატვის თავისუფლების შესახებ“-ის მიხედვით, რა არის ცილისწამების აუცილებელი შინაარსობრივი ნიშანი?', 'easy', 'სწორი პასუხია A, რადგან საქართველოს კანონი „სიტყვისა და გამოხატვის თავისუფლების შესახებ“ მუხლი 1 ადგენს, რომ ცილისწამება არის არსებითად მცდარი ფაქტის შემცველი და პირის სახელის გამტეხი განცხადება.', 'საქართველოს კანონი „სიტყვისა და გამოხატვის თავისუფლების შესახებ“', 'მუხლი 1', '', '2025-06-26', false, 'არსებითად მცდარი ფაქტი და პირის სახელის გამტეხი განცხადება', 'ნებისმიერი მკაცრი შეფასება, თუნდაც ფაქტს არ შეიცავდეს', 'მხოლოდ საჯარო სივრცეში წარმოთქმული უხამსი სიტყვა', 'ნებისმიერი ინფორმაცია, რომელიც ადმინისტრაციულ ორგანოს ეხება', 'A'),
    ('constitutional', 'freedom-of-expression', 'საქართველოს კანონი „სიტყვისა და გამოხატვის თავისუფლების შესახებ“-ის მიხედვით, როდის შეიძლება განცხადება შეფასდეს „უხამსობად“?', 'medium', 'სწორი პასუხია C, რადგან საქართველოს კანონი „სიტყვისა და გამოხატვის თავისუფლების შესახებ“ მუხლი 1 ადგენს, რომ უხამსობა არის განცხადება, რომელსაც არ აქვს პოლიტიკური, კულტურული, საგანმანათლებლო ან სამეცნიერო ღირებულება და უხეშად ლახავს ეთიკურ ნორმებს.', 'საქართველოს კანონი „სიტყვისა და გამოხატვის თავისუფლების შესახებ“', 'მუხლი 1', '', '2025-06-26', false, 'როცა იგი მკვეთრად აკრიტიკებს საჯარო პირს', 'როცა იგი სასამართლო პროცესზე გაკეთდა', 'როცა მას არ აქვს განსაზღვრული ღირებულება და უხეშად ლახავს ეთიკურ ნორმებს', 'როცა იგი შეიცავს მხოლოდ დადასტურებად ფაქტს', 'C'),
    ('constitutional', 'freedom-of-expression', 'საქართველოს კანონი „სიტყვისა და გამოხატვის თავისუფლების შესახებ“-ის მიხედვით, რას ნიშნავს „საზოგადოებრივი ყურადღება“?', 'medium', 'სწორი პასუხია B, რადგან საქართველოს კანონი „სიტყვისა და გამოხატვის თავისუფლების შესახებ“ მუხლი 1 ადგენს, რომ საზოგადოებრივი ყურადღება არის საზოგადოების ინტერესი და არა ცალკეულ პირთა უბრალო ცნობისმოყვარეობა.', 'საქართველოს კანონი „სიტყვისა და გამოხატვის თავისუფლების შესახებ“', 'მუხლი 1', '', '2025-06-26', false, 'ცალკეული პირების უბრალო ცნობისმოყვარეობას', 'საზოგადოების ინტერესს დემოკრატიულ თვითმმართველობასთან დაკავშირებული მოვლენისადმი', 'მედიის მიერ ნებისმიერი თემის მუდმივ გაშუქებას', 'საჯარო პირის მიმართ ყოველი კერძო ინტერესის არსებობას', 'B'),
