    ('constitutional', 'freedom-of-expression', 'საქართველოს კანონი „სიტყვისა და გამოხატვის თავისუფლების შესახებ“-ის მიხედვით, პირს არ იცოდა და არც შეიძლებოდა სცოდნოდა, რომ გავრცელებული ინფორმაცია ცილისწამება იყო. რა შედეგია სწორი?', 'medium', 'სწორი პასუხია A, რადგან საქართველოს კანონი „სიტყვისა და გამოხატვის თავისუფლების შესახებ“ მუხლი 16 ადგენს, რომ პირს ცილისწამებისთვის პასუხისმგებლობა არ ეკისრება, თუ მან არ იცოდა და არც შეიძლებოდა სცოდნოდა, რომ ცილისწამებას ავრცელებდა.', 'საქართველოს კანონი „სიტყვისა და გამოხატვის თავისუფლების შესახებ“', 'მუხლი 16', '', '2025-06-26', false, 'ცილისწამებისთვის პასუხისმგებლობა არ ეკისრება', 'ყოველთვის ეკისრება მორალური ზიანი', 'ყოველთვის უნდა მოიხადოს ბოდიში', 'სარჩელის ვადა 30 დღემდე მცირდება', 'A'),
    ('constitutional', 'freedom-of-expression', 'საქართველოს კანონი „სიტყვისა და გამოხატვის თავისუფლების შესახებ“-ის მიხედვით, სასამართლომ დაადგინა, რომ უარყოფის გამოქვეყნება არ არის საკმარისი ცილისწამებით მიყენებული ზიანის ასანაზღაურებლად. რა შეიძლება დაეკისროს მოპასუხეს?', 'hard', 'სწორი პასუხია B, რადგან საქართველოს კანონი „სიტყვისა და გამოხატვის თავისუფლების შესახებ“ მუხლი 17 ადგენს, რომ თუ შესწორება ან უარყოფა საკმარისი არ არის, მოპასუხეს შეიძლება დაეკისროს ქონებრივი ან/და მორალური ზიანის ანაზღაურება.', 'საქართველოს კანონი „სიტყვისა და გამოხატვის თავისუფლების შესახებ“', 'მუხლი 17', '', '2025-06-26', false, 'მხოლოდ ბოდიშის იძულებითი მოხდა', 'ქონებრივი ან/და არაქონებრივი ზიანის ანაზღაურება', 'წყაროს გამხელა ყველა შემთხვევაში', 'პოლიტიკური დებატების აკრძალვა', 'B'),
    ('constitutional', 'freedom-of-expression', 'საქართველოს კანონი „სიტყვისა და გამოხატვის თავისუფლების შესახებ“-ის მიხედვით, თუ ცილისწამების სარჩელი აშკარად უსაფუძვლოა და მიზნად სიტყვის თავისუფლების უკანონო შეზღუდვას ისახავს, რა შეუძლია მოპასუხეს?', 'medium', 'სწორი პასუხია C, რადგან საქართველოს კანონი „სიტყვისა და გამოხატვის თავისუფლების შესახებ“ მუხლი 18 ადგენს, რომ აშკარად უსაფუძვლო სარჩელისას მოპასუხეს შეუძლია მოითხოვოს გონივრულ ფარგლებში ფულადი ანაზღაურება.', 'საქართველოს კანონი „სიტყვისა და გამოხატვის თავისუფლების შესახებ“', 'მუხლი 18', '', '2025-06-26', false, 'მოითხოვოს მოსარჩელის საჯარო თანამდებობიდან გათავისუფლება', 'მოითხოვოს ჟურნალისტის წყაროს გამხელა', 'მოითხოვოს გონივრულ ფარგლებში ფულადი ანაზღაურება', 'მოითხოვოს კანონის ავტომატური გაუქმება', 'C'),
    ('constitutional', 'freedom-of-expression', 'საქართველოს კანონი „სიტყვისა და გამოხატვის თავისუფლების შესახებ“-ის მიხედვით, პირმა სადავო განცხადება 120 დღის წინ გაიცნო და ახლა სურს ცილისწამების სარჩელის შეტანა. რა პრობლემაა?', 'medium', 'სწორი პასუხია D, რადგან საქართველოს კანონი „სიტყვისა და გამოხატვის თავისუფლების შესახებ“ მუხლი 19 ადგენს, რომ ცილისწამების სარჩელი უნდა წარედგინოს 100 დღის განმავლობაში განცხადების გაცნობიდან ან გაცნობის შესაძლებლობიდან.', 'საქართველოს კანონი „სიტყვისა და გამოხატვის თავისუფლების შესახებ“', 'მუხლი 19', '', '2025-06-26', false, 'სარჩელი ჯერ ნაადრევია', 'სარჩელი მხოლოდ მედიას ეხება', 'სარჩელი მხოლოდ ბოდიშს მოითხოვს', '100-დღიანი სასარჩელო ხანდაზმულობის ვადა გასულია', 'D')
  ) as s(category_slug, subcategory_slug, text, difficulty, explanation, law_name, law_article, source_url, law_version_date, is_prime, option_a, option_b, option_c, option_d, correct_option)
  loop
    select id into v_article_id
    from public.law_articles
    where law_id = v_law_id and article_number = r.law_article;

    insert into public.questions(category_id, subcategory_id, text, difficulty, explanation, law_name, law_article, source_url, law_version_date, needs_review, is_prime, is_published, verified_at, law_id, primary_law_article_id)
    values (v_category_id, v_subcategory_id, r.text, r.difficulty::public.difficulty, r.explanation, r.law_name, r.law_article, nullif(r.source_url,''), r.law_version_date::date, false, r.is_prime, true, now(), v_law_id, v_article_id)
    returning id into v_question_id;

    insert into public.question_options(question_id, option_text, is_correct, sort_order) values
    (v_question_id, r.option_a, r.correct_option='A', 1),
    (v_question_id, r.option_b, r.correct_option='B', 2),
    (v_question_id, r.option_c, r.correct_option='C', 3),
    (v_question_id, r.option_d, r.correct_option='D', 4);

    insert into public.question_law_articles(question_id, law_article_id, is_primary)
    values (v_question_id, v_article_id, true)
    on conflict (question_id, law_article_id) do update set is_primary=true;
  end loop;
end $$;
